toolArgs.file_text:
.catalog-page {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
}

/* Filters */
.catalog-filters h4 {
    margin-top: 0;
}

.filter-section {
    margin-bottom: 1rem;
}

.filter-section h5 {
    margin: 0 0 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.price-inputs input {
    width: 80px;
    padding: 0.3rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.btn-apply,
.btn-clear {
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
}

.btn-apply {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.btn-clear {
    background: transparent;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #eee;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.3rem 0.5rem;
}

.results-summary {
    color: #666;
    font-size: 0.9rem;
}

/* Product Grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    border: 1px solid #ddd;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}

.product-image {
    background: #f0f0f0;
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 1rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.3rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: bold;
    color: #333;
}

.product-rating {
    color: #f5a623;
    margin-bottom: 0.4rem;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    padding: 0.5rem;
    background: #198754;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-add-to-cart:disabled {
    background: #ccc;
    cursor: not-allowed;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    justify-content: center;
    gap: 0.3rem;
    margin-top: 1.5rem;
    padding: 1rem 0;
}

.btn-page {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ddd;
    border-radius: 4px;
    background: white;
    cursor: pointer;
}

.btn-page.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.btn-page:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* States */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

.catalog-error button {
    margin-top: 1rem;
    padding: 0.5rem 1rem;
    border: 1px solid #dc3545;
    background: transparent;
    color: #dc3545;
    border-radius: 4px;
    cursor: pointer;
}

