+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-add-to-cart:disabled {
+    background: #ccc;
+    cursor: not-allowed;
+}
+
+/* Pagination */
+.catalog-pagination {
+    display: flex;
+    justify-content: center;
+    gap: 0.3rem;
+    margin-top: 1.5rem;
+    padding: 1rem 0;
+}
+
+.btn-page {
+    padding: 0.4rem 0.75rem;
+    border: 1px solid #ddd;
+    border-radius: 4px;
+    background: white;
+    cursor: pointer;
+}
+
+.btn-page.active {
+    background: #0d6efd;
+    color: white;
+    border-color: #0d6efd;
+}
+
+.btn-page:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* States */
+.catalog-loading,
+.catalog-empty,
+.catalog-error {
+    text-align: center;
+    padding: 3rem 1rem;
+    color: #666;
+}
+
+.catalog-error {
+    color: #dc3545;
+}
+
+.catalog-error button {
+    margin-top: 1rem;
+    padding: 0.5rem 1rem;
+    border: 1px solid #dc3545;
+    background: transparent;
+    color: #dc3545;
+    border-radius: 4px;
+    cursor: pointer;
+}
+

